const f = msg.payload || {};
let header = 'Everything is OK';
let detail = '';
let color = '#4caf50';
if (f.fault && f.fault !== 'ok') {
    header = f.fault.replace(/_/g, ' ').toUpperCase();
    detail = (f.recommended_first_check || '') + (f.safety_note ? '\n\n[SAFETY] ' + f.safety_note : '');
    color = f.confidence >= 0.85 ? '#f44336' : '#ff9800';
}
msg.payload = `**${header}**\n\n${detail}`;
msg.ui_update = {color};
return msg;

msg.url = 'http://fault-sim:8089/inject/' + msg.payload;
