msg.payload = {};
return msg;

const rows = (msg.payload || []).map(r => ({
  When: r.ts,
  Fault: (r.fault || '').replace(/_/g, ' '),
  Conf: r.confidence,
  Affected: (JSON.parse(r.affected_json || '[]') || []).join(', '),
}));
msg.payload = rows;
return msg;

// For the booth demo, call Groq directly. The full Supervisor at
// mira-pipeline:9099 owns intent + safety + FSM and is tuned for real
// technician chat — it short-circuits if the embedded fault context
// trips safety keywords, which makes booth demos messy. Production
// chat should still route through the Supervisor.
const fault = flow.get('current_fault') || {fault: 'ok'};
const question = msg.payload || '';
const evidence = (fault.evidence || []).map(e => `- ${e.topic}: ${JSON.stringify(e.value)}${e.note ? ' (' + e.note + ')' : ''}`).join('\n');
const affected = (fault.affected_components || []).join(', ');
const lower = question.toLowerCase();
if (/(^|\s)(yes|confirm|correct|ok|yep|yeah|y)(\s|$|[.!])/.test(lower)) {
    flow.set('confirmed_session', true);
}
const confirmedNow = flow.get('confirmed_session') || false;
const sys = [
    'You are MIRA — a calm, evidence-based maintenance supervisor.',
    'You answer briefly. You cite evidence. You never invent plant data.',
    '',
    'LIVE CONVEYOR STATE (Demo Cell / Conveyor CV-101):',
    '  active fault: ' + (fault.fault || 'ok'),
    '  confidence: ' + (fault.confidence || 0),
    '  affected components: ' + (affected || 'none'),
    '  evidence:',
    (evidence || '  (no evidence yet)'),
    '  recommended first check (raw): ' + (fault.recommended_first_check || 'n/a'),
    '  safety note (raw): ' + (fault.safety_note || 'standard plant PPE'),
    '',
    confirmedNow
        ? 'The technician has CONFIRMED the location. Reply directly with: diagnosis, confidence, evidence (bulleted), recommended first check, next measurement, safety note, work-order draft (one line). Under 180 words.'
        : 'MIRA protocol — first reply must be EXACTLY: "I believe you are working on Demo Cell / Conveyor CV-101 / ' + (affected || 'the suspected fault area') + '. Confirm?" — then stop. Do not diagnose until the technician says yes.',
].join('\n');
msg.url = 'https://api.groq.com/openai/v1/chat/completions';
msg.method = 'POST';
msg.headers = {
    'Content-Type': 'application/json',
    'Authorization': 'Bearer ' + env.get('GROQ_API_KEY'),
};
msg.payload = {
    model: 'llama-3.3-70b-versatile',
    messages: [
        {role: 'system', content: sys},
        {role: 'user', content: question},
    ],
    stream: false,
    temperature: 0.2,
    max_tokens: 400,
};
return msg;

let txt = '(no reply)';
try {
    if (msg.statusCode === 200 && msg.payload && msg.payload.choices && msg.payload.choices.length) {
        txt = msg.payload.choices[0].message.content || txt;
    } else if (msg.statusCode) {
        txt = '(MIRA pipeline returned ' + msg.statusCode + ')';
    }
} catch (e) { txt = '(parse error: ' + e.message + ')'; }
msg.payload = txt;
return msg;

